import{_ as l,C as r,o as n,c as s,a7 as e,E as d}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"覚醒体図鑑","description":"","frontmatter":{},"headers":[],"relativePath":"ja/awakeners/index.md","filePath":"ja/awakeners/index.md","lastUpdated":1775394001000}'),i={name:"ja/awakeners/index.md"};function o(h,t,g,c,x,y){const a=r("CharacterGrid");return n(),s("div",null,[t[0]||(t[0]=e('<h1 id="覚醒体図鑑" tabindex="-1">覚醒体図鑑 <a class="header-anchor" href="#覚醒体図鑑" aria-label="Permalink to &quot;覚醒体図鑑&quot;">​</a></h1><p>忘却前夜（Morimens）における<strong>覚醒体</strong>とは、プレイヤーが操作するキャラクターの総称です。各覚醒体は固有の界域・役割・カードセットを持ち、戦闘スタイルが大きく異なります。</p><h2 id="レアリティ" tabindex="-1">レアリティ <a class="header-anchor" href="#レアリティ" aria-label="Permalink to &quot;レアリティ&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">レアリティ</th><th style="text-align:center;">排出率</th><th style="text-align:left;">特徴</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="rarity-ssr">SSR</span></td><td style="text-align:center;">3%</td><td style="text-align:left;">最高レアリティ。固有スキル・専用カードが強力</td></tr><tr><td style="text-align:center;"><span class="rarity-sr">SR</span></td><td style="text-align:center;">15%</td><td style="text-align:left;">高レアリティ。啓霊を重ねることで十分な戦力に</td></tr><tr><td style="text-align:center;"><span class="rarity-r">R</span></td><td style="text-align:center;">82%</td><td style="text-align:left;">基本レアリティ。序盤の主力として活躍</td></tr></tbody></table><h2 id="界域-realm" tabindex="-1">界域（Realm） <a class="header-anchor" href="#界域-realm" aria-label="Permalink to &quot;界域（Realm）&quot;">​</a></h2><p>覚醒体はそれぞれ4つの界域のいずれかに属します。</p><table tabindex="0"><thead><tr><th style="text-align:center;">界域</th><th style="text-align:center;">英名</th><th style="text-align:left;">テーマ</th><th style="text-align:left;">特徴</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="realm-badge realm-chaos">混沌</span></td><td style="text-align:center;">Chaos</td><td style="text-align:left;">狂気・混乱</td><td style="text-align:left;">狂気ゲージの蓄積が速く、バーストに特化</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-aequor">深海</span></td><td style="text-align:center;">Aequor</td><td style="text-align:left;">深淵・海洋</td><td style="text-align:left;">防御・回復に優れたコントロール型</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-caro">血肉</span></td><td style="text-align:center;">Caro</td><td style="text-align:left;">変容・肉体</td><td style="text-align:left;">高HP・自傷ギミックで爆発的火力</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-ultra">超維</span></td><td style="text-align:center;">Ultra</td><td style="text-align:left;">次元・超越</td><td style="text-align:left;">テクニカルな算力操作とカードドローに特化</td></tr></tbody></table><h2 id="役割-ロール" tabindex="-1">役割（ロール） <a class="header-anchor" href="#役割-ロール" aria-label="Permalink to &quot;役割（ロール）&quot;">​</a></h2><ul><li><strong>攻撃型</strong> — 高火力アタッカー。敵を速やかに撃破する</li><li><strong>防御型</strong> — タンク・シールド付与。味方を守る盾役</li><li><strong>支援型</strong> — バフ・デバフ・回復。編成の潤滑油</li><li><strong>妨害型</strong> — 状態異常・コントロール。敵の行動を制限</li></ul><h2 id="基本ステータス" tabindex="-1">基本ステータス <a class="header-anchor" href="#基本ステータス" aria-label="Permalink to &quot;基本ステータス&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">ステータス</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;">HP</td><td style="text-align:left;">体力。0になると戦闘不能</td></tr><tr><td style="text-align:left;">攻撃力</td><td style="text-align:left;">カードの基礎ダメージに影響</td></tr><tr><td style="text-align:left;">防御力</td><td style="text-align:left;">受けるダメージを軽減</td></tr><tr><td style="text-align:left;">速度</td><td style="text-align:left;">行動順序を決定</td></tr><tr><td style="text-align:left;">狂気耐性</td><td style="text-align:left;">狂気（Madness）の蓄積速度に影響</td></tr></tbody></table><h2 id="カード構成" tabindex="-1">カード構成 <a class="header-anchor" href="#カード構成" aria-label="Permalink to &quot;カード構成&quot;">​</a></h2><p>各覚醒体は以下のカードを所持します。</p><ul><li><strong>指令カード</strong>（Command Card）— 通常攻撃・スキルに相当する基本カード</li><li><strong>魂覚醒カード</strong>（Spirit Awakening Card）— 狂気ゲージ100到達時に発動可能な必殺カード</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>覚醒体の詳細な一覧は<a href="./list.html">覚醒体一覧</a>をご覧ください。育成方法は<a href="./leveling.html">育成ガイド</a>で解説しています。</p></div><h2 id="覚醒体一覧" tabindex="-1">覚醒体一覧 <a class="header-anchor" href="#覚醒体一覧" aria-label="Permalink to &quot;覚醒体一覧&quot;">​</a></h2><p>界域・役割・レアリティで絞り込みできます。</p>',17)),d(a),t[1]||(t[1]=e('<h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./list.html">覚醒体一覧</a></li><li><a href="./leveling.html">育成ガイド</a></li><li><a href="./enlightenment.html">啓霊システム</a></li><li><a href="./team-building.html">編成ガイド</a></li><li><a href="./../realms/">界域概要</a></li></ul>',2))])}const p=l(i,[["render",o]]);export{m as __pageData,p as default};
